<template><div class="relative h-56 rounded-xl overflow-hidden"><img :src="current.image_path||'/assets/banners/banner1.svg'" class="w-full h-full object-cover"><div class="absolute inset-0 bg-black/30 text-white p-6"><h2 class="text-3xl font-bold">{{current.title||'Welcome Back'}}</h2><p>{{current.subtitle}}</p><button class="mt-4 bg-black/70 px-4 py-2 rounded-lg">Explore updates</button></div><div class="absolute bottom-3 left-1/2 -translate-x-1/2 flex gap-2"><button v-for="(b,i) in items" @click="idx=i" class="w-2 h-2 rounded-full" :class="idx===i?'bg-white':'bg-white/50'"></button></div></div></template>
<script setup>import { computed, ref, watchEffect } from 'vue'; const props=defineProps({items:{type:Array,default:()=>[]}}); const idx=ref(0); const current=computed(()=>props.items[idx.value]||{}); watchEffect(()=>{ if(idx.value>=props.items.length) idx.value=0;});</script>
